import random

def random_walk_2d(steps):
    x, y = 0, 0
    for _ in range(steps):
        direction = random.choice(['N', 'S', 'E', 'W'])
        if direction == 'N':
            y += 1
        elif direction == 'S':
            y -= 1
        elif direction == 'E':
            x += 1
        elif direction == 'W':
            x -= 1
    return (x, y)

# Example usage:
final_position = random_walk_2d(100)
print(f"Final position after 100 steps: {final_position}")
